import { useState, useEffect, useCallback, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import API from "../../api";

export default function WaiterPanel() {
  const [tables, setTables] = useState([]);
  const [menu, setMenu] = useState([]);
  const [specials, setSpecials] = useState({});
  const [selectedTable, setSelectedTable] = useState(null);
  // allRounds: [{order, items, roundNumber}]  — persisted from DB every time table is opened
  const [allRounds, setAllRounds] = useState([]);
  const [draftRoundIdx, setDraftRoundIdx] = useState(null); // index into allRounds of current editable draft
  const [loading, setLoading] = useState(true);
  const [roundLoading, setRoundLoading] = useState(false);
  const [view, setView] = useState("tables");
  const [confirmModal, setConfirmModal] = useState(false);
  const [confirming, setConfirming] = useState(false);
  const [activeOrderType, setActiveOrderType] = useState("table"); // 'table' or 'takeaway'
  const [taxSettings, setTaxSettings] = useState({ tax_enabled: true, tax_rate: 13 });
  const { user, logout, theme, toggleTheme } = useAuth();
  const navigate = useNavigate();
  const summaryRef = useRef(null);

  const loadData = useCallback(async () => {
    try {
      const [t, m, s] = await Promise.all([
        API.get("/tables"),
        API.get("/menu"),
        API.get("/extras/specials"),
      ]);
      setTables(t.data);
      setMenu(m.data.filter(i => i.is_available));
      const sMap = {};
      s.data.forEach(sp => {
        sMap[sp.menu_id] = {
          ...sp,
          discounted_price: sp.discount_pct > 0
            ? Math.round(sp.price * (1 - sp.discount_pct / 100))
            : sp.price,
        };
      });
      setSpecials(sMap);
    } catch {}
    setLoading(false);
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  useEffect(() => {
    API.get("/extras/tax-settings").then(r => setTaxSettings(r.data)).catch(() => {});
  }, []);

  // Load all rounds for a table from the API
  const loadTableRounds = useCallback(async (table) => {
    setRoundLoading(true);
    try {
      const allOrdersRes = await API.get(`/orders/table/${table.id}/all`);
      const orders = allOrdersRes.data || [];

      if (orders.length === 0) {
        setAllRounds([]);
        setDraftRoundIdx(null);
        setRoundLoading(false);
        return;
      }

      // Load items for each order in parallel
      const roundsWithItems = await Promise.all(
        orders.map(async (order, idx) => {
          try {
            const detail = await API.get(`/orders/${order.id}`);
            return {
              order: detail.data.order,
              items: detail.data.items || [],
              roundNumber: idx + 1,
            };
          } catch {
            return { order, items: [], roundNumber: idx + 1 };
          }
        })
      );

      setAllRounds(roundsWithItems);

      // Find the draft round (if any)
      const draftIdx = roundsWithItems.findIndex(r => r.order.status === "draft");
      setDraftRoundIdx(draftIdx === -1 ? null : draftIdx);
    } catch {}
    setRoundLoading(false);
  }, []);

  const selectTable = async (table) => {
    setSelectedTable(table);
    setActiveOrderType("table");
    setView("order");
    await loadTableRounds(table);
  };

  // Refresh a single round's data
  const refreshRound = async (roundIdx) => {
    const round = allRounds[roundIdx];
    if (!round) return;
    try {
      const detail = await API.get(`/orders/${round.order.id}`);
      setAllRounds(prev => {
        const updated = [...prev];
        updated[roundIdx] = {
          ...updated[roundIdx],
          order: detail.data.order,
          items: detail.data.items || [],
        };
        return updated;
      });
    } catch {}
  };

  const startOrder = async () => {
    if (!selectedTable) return;
    setRoundLoading(true);
    try {
      const res = await API.post("/orders", { table_id: selectedTable.id, order_type: "table" });
      const newRound = { order: res.data, items: [], roundNumber: 1 };
      setAllRounds([newRound]);
      setDraftRoundIdx(0);
      await loadData();
    } catch (err) {
      // Table may already have an order — reload from DB
      if (err.response?.data?.order_id) {
        await loadTableRounds(selectedTable);
      }
    }
    setRoundLoading(false);
  };

  const startNewRound = async () => {
    if (!selectedTable) return;
    // Ensure all existing rounds are sent (no draft)
    const hasDraft = allRounds.some(r => r.order.status === "draft");
    if (hasDraft) return;
    setRoundLoading(true);
    try {
      const res = await API.post("/orders", {
        table_id: selectedTable.id,
        order_type: "table",
        addendum: true,
      });
      const newRound = { order: res.data, items: [], roundNumber: allRounds.length + 1 };
      setAllRounds(prev => [...prev, newRound]);
      setDraftRoundIdx(allRounds.length);
      // Scroll summary to bottom to show new round
      setTimeout(() => {
        summaryRef.current?.scrollTo({ top: summaryRef.current.scrollHeight, behavior: "smooth" });
      }, 200);
    } catch {}
    setRoundLoading(false);
  };

  const startTakeaway = async () => {
    setRoundLoading(true);
    try {
      const res = await API.post("/orders", { order_type: "takeaway" });
      const newRound = { order: res.data, items: [], roundNumber: 1 };
      setAllRounds([newRound]);
      setDraftRoundIdx(0);
      setSelectedTable(null);
      setActiveOrderType("takeaway");
    } catch {}
    setRoundLoading(false);
    setView("order");
  };

  const addItem = async (menuItem) => {
    if (draftRoundIdx === null) return;
    const draftRound = allRounds[draftRoundIdx];
    if (!draftRound || draftRound.order.status !== "draft") return;

    const special = specials[menuItem.id];
    const unit_price = special ? special.discounted_price : menuItem.price;

    try {
      await API.post(`/orders/${draftRound.order.id}/items`, {
        menu_id: menuItem.id,
        quantity: 1,
        unit_price,
      });
      await refreshRound(draftRoundIdx);
    } catch {}
  };

  const removeItem = async (itemId) => {
    if (draftRoundIdx === null) return;
    const draftRound = allRounds[draftRoundIdx];
    if (!draftRound || draftRound.order.status !== "draft") return;
    try {
      await API.delete(`/orders/${draftRound.order.id}/items/${itemId}`);
      await refreshRound(draftRoundIdx);
    } catch {}
  };

  const handleSendToKitchen = async () => {
    if (draftRoundIdx === null) return;
    const draftRound = allRounds[draftRoundIdx];
    if (!draftRound || draftRound.items.length === 0) return;
    setConfirming(true);
    try {
      await API.put(`/orders/${draftRound.order.id}/confirm`);
      // Refresh only this round
      await refreshRound(draftRoundIdx);
      setDraftRoundIdx(null);
      setConfirmModal(false);
      await loadData();
    } catch {}
    setConfirming(false);
  };

  const handleLogout = async () => {
    try { await API.post("/auth/logout"); } catch {}
    logout(); navigate("/");
  };

  const goBack = () => {
    setView("tables");
    setAllRounds([]);
    setDraftRoundIdx(null);
    setSelectedTable(null);
    loadData();
  };

  // Computed values
  const categories = [...new Set(menu.map(m => m.category))];
  const catIcons = { food: "🍛", drink: "🥤", dessert: "🍰", snack: "🍿" };
  const roundColors = ["#6366f1", "#10b981", "#f59e0b", "#ec4899", "#06b6d4", "#8b5cf6"];
  const combinedTotal = allRounds.reduce((sum, r) => sum + Number(r.order?.total || 0), 0);
  const taxRate = parseFloat(taxSettings.tax_rate) || 13;
  const taxEnabled = taxSettings.tax_enabled !== false;
  const taxAmount = taxEnabled ? parseFloat((combinedTotal * taxRate / 100).toFixed(2)) : 0;
  const grandTotalWithTax = parseFloat((combinedTotal + taxAmount).toFixed(2));
  const hasSentRounds = allRounds.some(r => r.order.status !== "draft");
  const draftRound = draftRoundIdx !== null ? allRounds[draftRoundIdx] : null;
  const canAddItems = draftRound !== null && draftRound.order.status === "draft";

  const getRoundLabel = (idx) => {
    const labels = ["Round 1", "Round 2", "Round 3", "Round 4", "Round 5", "Round 6", "Round 7", "Round 8"];
    return labels[idx] || `Round ${idx + 1}`;
  };
  const getRoundOrdinal = (idx) => {
    const ordinals = ["1st", "2nd", "3rd", "4th", "5th", "6th", "7th", "8th"];
    return ordinals[idx] || `${idx + 1}th`;
  };

  return (
    <div style={{ minHeight: "100vh", background: "var(--bg-base)", display: "flex", flexDirection: "column" }}>
      {/* HEADER */}
      <header style={{
        background: "var(--bg-sidebar)", borderBottom: "1px solid var(--border)",
        padding: "12px 24px", display: "flex", alignItems: "center", justifyContent: "space-between",
        flexShrink: 0,
      }}>
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <div style={{
            width: 38, height: 38, background: "var(--gradient-brand)", borderRadius: 10,
            display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18,
          }}>🧑‍🍽️</div>
          <div>
            <div style={{ fontWeight: 700, fontSize: 15 }}>Waiter Panel</div>
            <div style={{ fontSize: 11, color: "var(--text-muted)" }}>{user?.restaurant_name} · {user?.name}</div>
          </div>
        </div>
        <div style={{ display: "flex", gap: 8 }}>
          {view === "order" && (
            <button className="btn btn-secondary btn-sm" onClick={goBack}>← Tables</button>
          )}
          <button className="theme-toggle" onClick={toggleTheme}>
            <span>{theme === "dark" ? "🌙" : "☀️"}</span>
            <div className="toggle-track"><div className="toggle-thumb" /></div>
          </button>
          <button className="btn btn-ghost btn-sm" onClick={handleLogout}>🚪</button>
        </div>
      </header>

      <div style={{ flex: 1, overflow: "auto", padding: 20 }}>

        {/* ── TABLES VIEW ─────────────────────────────────────────────── */}
        {view === "tables" && (
          <>
            <div style={{ marginBottom: 20, display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 10 }}>
              <div style={{ fontSize: 18, fontWeight: 700 }}>Select a Table</div>
              <div style={{ display: "flex", gap: 8 }}>
                <button
                  className="btn btn-primary"
                  onClick={startTakeaway}
                  style={{ background: "linear-gradient(135deg,#f59e0b,#d97706)", border: "none", fontWeight: 800, display: "flex", alignItems: "center", gap: 6 }}
                >
                  📦 New Takeaway Order
                </button>
                <button className="btn btn-secondary btn-sm" onClick={loadData}>↻ Refresh</button>
              </div>
            </div>

            {Object.keys(specials).length > 0 && (
              <div style={{
                background: "linear-gradient(135deg,var(--warning-bg),#fef9c3)",
                border: "1px solid var(--warning)", borderRadius: 12, padding: "12px 16px",
                marginBottom: 20, display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap",
              }}>
                <span style={{ fontSize: 18 }}>⭐</span>
                <span style={{ fontWeight: 700, color: "var(--warning)", fontSize: 13 }}>Today's Specials:</span>
                {Object.values(specials).map((sp, i) => (
                  <span key={i} style={{
                    background: "var(--warning)", color: "#fff", borderRadius: 20,
                    padding: "3px 10px", fontSize: 12, fontWeight: 700,
                  }}>
                    {sp.name} — Rs.{sp.discounted_price} {sp.label && `"${sp.label}"`}
                    {sp.discount_pct > 0 && ` (${sp.discount_pct}% off)`}
                  </span>
                ))}
              </div>
            )}

            {loading ? (
              <div className="flex-center" style={{ padding: 60 }}><div className="spinner" /></div>
            ) : (
              <div className="table-grid">
                {tables.map(t => (
                  <div key={t.id} className={`table-tile ${t.status}`} onClick={() => selectTable(t)} style={{ cursor: "pointer" }}>
                    <div className="tile-num">T{t.table_number}</div>
                    <div className="tile-status">{t.status}</div>
                    {t.status === "reserved" && t.reserved_by_name && (
                      <div style={{ fontSize: 10, color: "var(--accent-light)", marginTop: 3, fontWeight: 600 }}>
                        📋 {t.reserved_by_name}
                      </div>
                    )}
                    <div style={{ fontSize: 11, color: "var(--text-muted)", marginTop: 4 }}>👥 {t.capacity}</div>
                  </div>
                ))}
                {tables.length === 0 && (
                  <div className="empty-state"><div className="empty-icon">🪑</div><h3>No tables configured</h3></div>
                )}
              </div>
            )}
          </>
        )}

        {/* ── ORDER VIEW ──────────────────────────────────────────────── */}
        {view === "order" && (
          <div style={{ display: "grid", gridTemplateColumns: "1fr 390px", gap: 20, minHeight: "100%" }}>

            {/* LEFT: MENU */}
            <div>
              {/* Table / Takeaway badge */}
              <div style={{ marginBottom: 16, display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap" }}>
                {activeOrderType === "takeaway" ? (
                  <div style={{ background: "linear-gradient(135deg,#f59e0b,#d97706)", color: "#fff", borderRadius: 10, padding: "8px 18px", fontWeight: 900, fontSize: 16, display: "inline-flex", alignItems: "center", gap: 8 }}>
                    📦 TAKEAWAY ORDER
                  </div>
                ) : (
                  <div style={{ background: "var(--gradient-brand)", color: "#fff", borderRadius: 10, padding: "8px 18px", fontWeight: 800, fontSize: 15, display: "inline-flex", alignItems: "center", gap: 8 }}>
                    🪑 Table {selectedTable?.table_number} — Menu
                  </div>
                )}

                {/* Round status badges */}
                {allRounds.map((r, idx) => (
                  r.order.status !== "draft" && (
                    <span key={idx} style={{
                      background: `${roundColors[idx % roundColors.length]}20`,
                      color: roundColors[idx % roundColors.length],
                      border: `1px solid ${roundColors[idx % roundColors.length]}50`,
                      borderRadius: 20, padding: "4px 12px", fontSize: 12, fontWeight: 700,
                    }}>
                      ✅ {getRoundLabel(idx)} sent
                    </span>
                  )
                ))}

                {draftRoundIdx !== null && (
                  <span style={{
                    background: "rgba(245,158,11,0.15)", color: "#d97706",
                    border: "1px solid rgba(245,158,11,0.4)",
                    borderRadius: 20, padding: "4px 12px", fontSize: 12, fontWeight: 700,
                  }}>
                    ✏️ Taking {getRoundOrdinal(draftRoundIdx)} order
                  </span>
                )}
              </div>

              {roundLoading ? (
                <div className="flex-center" style={{ padding: 60 }}><div className="spinner" /></div>
              ) : allRounds.length === 0 ? (
                /* No orders yet — start first order */
                <div style={{ textAlign: "center", padding: 40 }}>
                  <div style={{ fontSize: 48, marginBottom: 12 }}>🪑</div>
                  <div style={{ fontWeight: 600, marginBottom: 8 }}>
                    {activeOrderType === "takeaway" ? "New Takeaway Order" : `Table ${selectedTable?.table_number} is free`}
                  </div>
                  {activeOrderType === "table" && (
                    <button className="btn btn-primary" onClick={startOrder}>🍽️ Start New Order</button>
                  )}
                </div>
              ) : (
                <>
                  {/* "Add Another Round" prompt — only shown when no draft round */}
                  {hasSentRounds && draftRoundIdx === null && activeOrderType !== "takeaway" && (
                    <div style={{
                      marginBottom: 16,
                      background: "linear-gradient(135deg,rgba(99,102,241,0.08),rgba(139,92,246,0.05))",
                      border: "1px solid var(--accent)", borderRadius: 12, padding: "14px 18px",
                      display: "flex", alignItems: "center", justifyContent: "space-between", gap: 12,
                    }}>
                      <div>
                        <div style={{ fontWeight: 700, fontSize: 14 }}>Need more items?</div>
                        <div style={{ fontSize: 12, color: "var(--text-muted)", marginTop: 2 }}>
                          Start a new round — only new items are sent to the kitchen.
                        </div>
                      </div>
                      <button
                        className="btn btn-primary btn-sm"
                        onClick={startNewRound}
                        style={{ whiteSpace: "nowrap", fontWeight: 800 }}
                      >
                        ➕ Add {getRoundOrdinal(allRounds.length)} Order
                      </button>
                    </div>
                  )}

                  {/* Menu grid — disabled when no draft round */}
                  {categories.map(cat => {
                    const items = menu.filter(m => m.category === cat);
                    return (
                      <div key={cat} style={{ marginBottom: 20 }}>
                        <div style={{ fontSize: 13, fontWeight: 700, color: "var(--text-muted)", textTransform: "uppercase", letterSpacing: 1, marginBottom: 10 }}>
                          {catIcons[cat]} {cat}
                        </div>
                        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(165px,1fr))", gap: 10 }}>
                          {items.map(item => {
                            const special = specials[item.id];
                            const displayPrice = special ? special.discounted_price : item.price;
                            return (
                              <button
                                key={item.id}
                                onClick={() => addItem(item)}
                                disabled={!canAddItems}
                                style={{
                                  background: special ? "linear-gradient(135deg,#fefce8,#fef9c3)" : "var(--bg-card)",
                                  border: `1px solid ${special ? "var(--warning)" : "var(--border)"}`,
                                  borderRadius: 10, padding: "12px 14px",
                                  cursor: canAddItems ? "pointer" : "not-allowed",
                                  textAlign: "left", transition: "all 0.2s ease",
                                  color: "var(--text-primary)", opacity: canAddItems ? 1 : 0.45,
                                  position: "relative",
                                }}
                                onMouseOver={e => { if (canAddItems) { e.currentTarget.style.borderColor = "var(--accent)"; e.currentTarget.style.transform = "translateY(-2px)"; }}}
                                onMouseOut={e => { e.currentTarget.style.borderColor = special ? "var(--warning)" : "var(--border)"; e.currentTarget.style.transform = "translateY(0)"; }}
                              >
                                {special && (
                                  <div style={{ position: "absolute", top: -8, right: 8, background: "var(--warning)", color: "#fff", fontSize: 9, fontWeight: 800, borderRadius: 20, padding: "2px 7px", letterSpacing: 0.5 }}>
                                    {special.label || `${special.discount_pct}% OFF`}
                                  </div>
                                )}
                                <div style={{ fontWeight: 600, fontSize: 13, marginBottom: 4 }}>{item.name}</div>
                                <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                                  <span style={{ color: "var(--success)", fontWeight: 700, fontSize: 13 }}>Rs. {Number(displayPrice).toLocaleString()}</span>
                                  {special && special.discount_pct > 0 && (
                                    <span style={{ textDecoration: "line-through", fontSize: 11, color: "var(--text-muted)" }}>Rs. {Number(item.price).toLocaleString()}</span>
                                  )}
                                </div>
                              </button>
                            );
                          })}
                        </div>
                      </div>
                    );
                  })}
                </>
              )}
            </div>

            {/* RIGHT: ORDER SUMMARY */}
            <div style={{ position: "sticky", top: 0, alignSelf: "start" }}>
              <div className="order-panel">
                <div className="order-panel-header">
                  <div>
                    <div style={{ fontWeight: 700 }}>Order Summary</div>
                    <div style={{ fontSize: 11, color: "var(--text-muted)" }}>
                      {activeOrderType === "takeaway"
                        ? "📦 Takeaway"
                        : selectedTable
                        ? `Table ${selectedTable.table_number} · ${allRounds.length} round${allRounds.length !== 1 ? "s" : ""}`
                        : "No active order"}
                    </div>
                  </div>
                  {allRounds.length > 0 && (
                    <span style={{
                      background: "var(--success-bg)", color: "var(--success)",
                      border: "1px solid var(--success)", borderRadius: 20, padding: "3px 10px", fontSize: 11, fontWeight: 700,
                    }}>
                      {allRounds.filter(r => r.order.status !== "draft").length}/{allRounds.length} sent
                    </span>
                  )}
                </div>

                {/* Scrollable rounds list */}
                <div ref={summaryRef} style={{ maxHeight: "calc(100vh - 300px)", overflow: "auto" }}>
                  {allRounds.length === 0 && (
                    <div style={{ padding: "30px 20px", textAlign: "center", color: "var(--text-muted)", fontSize: 13 }}>
                      {activeOrderType === "table" ? "Start an order to see items here" : "Add items to takeaway order"}
                    </div>
                  )}

                  {allRounds.map((round, idx) => {
                    const isSent = round.order.status !== "draft";
                    const isDraft = round.order.status === "draft";
                    const color = roundColors[idx % roundColors.length];
                    return (
                      <div key={round.order.id}>
                        {/* Round header */}
                        <div style={{
                          padding: "8px 16px",
                          background: isDraft ? `${color}12` : "var(--bg-surface)",
                          borderBottom: "1px solid var(--border)",
                          borderTop: idx > 0 ? "2px solid var(--border)" : "none",
                          display: "flex", justifyContent: "space-between", alignItems: "center",
                        }}>
                          <span style={{ fontSize: 12, fontWeight: 800, color: isDraft ? color : "var(--text-muted)", textTransform: "uppercase", letterSpacing: 0.5 }}>
                            {getRoundLabel(idx)}
                            {isDraft && <span style={{ fontWeight: 600, textTransform: "none", marginLeft: 6, fontSize: 11 }}>(adding items...)</span>}
                          </span>
                          {isSent ? (
                            <span style={{ fontSize: 11, color: "var(--success)", fontWeight: 700 }}>✅ Sent to kitchen</span>
                          ) : (
                            <span style={{ fontSize: 11, color: color, fontWeight: 600 }}>✏️ Draft</span>
                          )}
                        </div>

                        {/* Items */}
                        <div className="order-items-list">
                          {round.items.length === 0 ? (
                            <div style={{ padding: "14px 16px", textAlign: "center", color: "var(--text-muted)", fontSize: 12 }}>
                              Tap menu items to add
                            </div>
                          ) : round.items.map(item => (
                            <div key={item.id} className="order-item-row" style={{ background: isDraft ? `${color}06` : "transparent" }}>
                              <div style={{ flex: 1 }}>
                                <div style={{ fontWeight: 600, fontSize: 13 }}>{item.name}</div>
                                <div style={{ fontSize: 11, color: "var(--text-muted)" }}>×{item.quantity}</div>
                              </div>
                              <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                                <span style={{ fontWeight: 700, color: isDraft ? color : "var(--success)", fontSize: 13 }}>
                                  Rs. {Number(item.price).toLocaleString()}
                                </span>
                                {isDraft && (
                                  <button
                                    onClick={() => removeItem(item.id)}
                                    style={{ background: "none", border: "none", cursor: "pointer", color: "var(--danger)", fontSize: 16, padding: 2 }}
                                  >×</button>
                                )}
                              </div>
                            </div>
                          ))}
                        </div>

                        {/* Round subtotal */}
                        <div style={{ padding: "7px 16px", display: "flex", justifyContent: "space-between", fontSize: 12, borderBottom: "1px solid var(--border)", background: "var(--bg-surface)" }}>
                          <span style={{ color: "var(--text-muted)" }}>{getRoundLabel(idx)} total</span>
                          <span style={{ fontWeight: 700, color: isSent ? "var(--text-primary)" : color }}>
                            Rs. {Number(round.order?.total || 0).toLocaleString()}
                          </span>
                        </div>
                      </div>
                    );
                  })}
                </div>

                {/* COMBINED TOTAL */}
                {allRounds.length > 0 && (
                  <div className="order-total-bar">
                    <div style={{ flex: 1 }}>
                      {taxEnabled && (
                        <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: "var(--text-muted)", marginBottom: 4 }}>
                          <span>Subtotal</span>
                          <span>Rs. {combinedTotal.toLocaleString()}</span>
                        </div>
                      )}
                      {taxEnabled && (
                        <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: "var(--text-muted)", marginBottom: 6 }}>
                          <span>VAT ({taxRate}%)</span>
                          <span>Rs. {taxAmount.toLocaleString()}</span>
                        </div>
                      )}
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                        <div>
                          <div style={{ fontWeight: 700, fontSize: 14 }}>Grand Total</div>
                          {taxEnabled && (
                            <div style={{ fontSize: 10, color: "var(--text-muted)", marginTop: 1 }}>VAT inclusive</div>
                          )}
                        </div>
                        <span style={{ color: "var(--success)", fontSize: 18, fontWeight: 900 }}>
                          Rs. {grandTotalWithTax.toLocaleString()}
                        </span>
                      </div>
                    </div>
                  </div>
                )}

                {/* SEND TO KITCHEN BUTTON */}
                {draftRound && draftRound.items.length > 0 && (
                  <div style={{ padding: "12px 16px", borderTop: "1px solid var(--border)" }}>
                    <button
                      className="btn btn-primary"
                      style={{
                        width: "100%", fontWeight: 800, fontSize: 15, padding: "12px 0",
                        background: `linear-gradient(135deg, ${roundColors[draftRoundIdx % roundColors.length]}, ${roundColors[(draftRoundIdx + 1) % roundColors.length]})`,
                      }}
                      onClick={() => setConfirmModal(true)}
                    >
                      🚀 Send {getRoundLabel(draftRoundIdx)} to Kitchen
                    </button>
                    <div style={{ fontSize: 11, color: "var(--text-muted)", textAlign: "center", marginTop: 6 }}>
                      Only these new items will be sent — no duplication
                    </div>
                  </div>
                )}

                {/* All rounds sent message */}
                {allRounds.length > 0 && draftRoundIdx === null && (
                  <div style={{ padding: "12px 16px", borderTop: "1px solid var(--border)" }}>
                    <div style={{
                      background: "var(--success-bg)", border: "1px solid var(--success)",
                      borderRadius: 10, padding: "10px 14px", textAlign: "center",
                      color: "var(--success)", fontWeight: 700, fontSize: 13, marginBottom: 8,
                    }}>
                      ✅ All rounds sent to kitchen
                    </div>
                    {activeOrderType !== "takeaway" && (
                      <button
                        className="btn btn-secondary btn-sm"
                        style={{ width: "100%", fontWeight: 700 }}
                        onClick={startNewRound}
                      >
                        ➕ Add {getRoundOrdinal(allRounds.length)} Order
                      </button>
                    )}
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </div>

      {/* CONFIRM SEND MODAL */}
      {confirmModal && draftRound && (
        <div className="modal-overlay" onClick={() => setConfirmModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()} style={{ maxWidth: 440 }}>
            <div className="modal-header">
              <h3>🚀 Send {getRoundLabel(draftRoundIdx)} to Kitchen</h3>
              <button className="modal-close" onClick={() => setConfirmModal(false)}>✕</button>
            </div>
            <div className="modal-body">
              <div style={{ textAlign: "center", marginBottom: 14 }}>
                <div style={{ fontSize: 40, marginBottom: 10 }}>
                  {activeOrderType === "takeaway" ? "📦" : draftRoundIdx === 0 ? "🍽️" : "➕"}
                </div>
                <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 4 }}>
                  {activeOrderType === "takeaway"
                    ? "Send Takeaway to Kitchen?"
                    : draftRoundIdx === 0
                    ? `Send 1st Order for Table ${selectedTable?.table_number}?`
                    : `Send ${getRoundOrdinal(draftRoundIdx)} order for Table ${selectedTable?.table_number}?`}
                </div>
                {draftRoundIdx > 0 && (
                  <div style={{ color: "var(--text-muted)", fontSize: 13 }}>
                    Only these new items will go to kitchen — previous rounds are excluded.
                  </div>
                )}
              </div>

              <div style={{ background: "var(--bg-surface)", borderRadius: 10, padding: 14, border: "1px solid var(--border)" }}>
                <div style={{ fontSize: 11, fontWeight: 700, color: "var(--text-muted)", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 10 }}>
                  Items for {getRoundLabel(draftRoundIdx)}
                </div>
                {draftRound.items.map((item, i) => (
                  <div key={i} style={{ display: "flex", justifyContent: "space-between", fontSize: 13, padding: "4px 0" }}>
                    <span>{item.name} <span style={{ color: "var(--text-muted)" }}>×{item.quantity}</span></span>
                    <span style={{ fontWeight: 600 }}>Rs. {Number(item.price).toLocaleString()}</span>
                  </div>
                ))}
                <div style={{ display: "flex", justifyContent: "space-between", fontWeight: 800, fontSize: 15, borderTop: "1px solid var(--border)", marginTop: 8, paddingTop: 8, color: "var(--success)" }}>
                  <span>{getRoundLabel(draftRoundIdx)} Total</span>
                  <span>Rs. {Number(draftRound.order?.total || 0).toLocaleString()}</span>
                </div>
                {allRounds.length > 1 && (
                  <div style={{ marginTop: 8, borderTop: "1px dashed var(--border)", paddingTop: 8 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: "var(--text-muted)", marginBottom: 3 }}>
                      <span>All rounds subtotal</span>
                      <span>Rs. {combinedTotal.toLocaleString()}</span>
                    </div>
                    {taxEnabled && (
                      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: "var(--text-muted)", marginBottom: 3 }}>
                        <span>VAT ({taxRate}%)</span>
                        <span>Rs. {taxAmount.toLocaleString()}</span>
                      </div>
                    )}
                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, fontWeight: 800, color: "var(--success)" }}>
                      <span>Grand Total (incl. VAT)</span>
                      <span>Rs. {grandTotalWithTax.toLocaleString()}</span>
                    </div>
                  </div>
                )}
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-ghost" onClick={() => setConfirmModal(false)}>Cancel</button>
              <button className="btn btn-primary" style={{ fontWeight: 800 }} onClick={handleSendToKitchen} disabled={confirming}>
                {confirming ? <><span className="spinner-sm" /> Sending...</> : `✅ Confirm & Send`}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
